mapper.select:
select * from t_finance_order where 1=1

    and party_id=#{partyId}



    AND t_finance_order.state in('0','2')



    AND t_finance_order.state=#{state}


order by create_time desc

select * from t_finance_order where 1=1

    and create_time=#{date}


order by create_time desc

SELECT financeOrder.uuid id,financeOrder.order_no order_no ,financeOrder.finance_id financeId , financeOrder.amount amount,financeOrder.create_time create_time, financeOrder.close_time close_time,financeOrder.profit profit, financeOrder.state state, party.user_name username,party.user_code usercode,party.role_name rolename, finance.name,finance.name_en, finance.name_kn,finance.name_jn FROM t_finance_order financeOrder LEFT JOIN tz_user party ON financeOrder.party_id = party.user_id LEFT JOIN t_finance finance ON finance.uuid = financeOrder.finance_id WHERE 1 = 1
AND (party.user_name like CONCAT('%', #{name_para}, '%') OR party.user_code like CONCAT('%', #{name_para}, '%') )
and (finance.name=#{finance_para} or finance.name_en =#{finance_para} or finance.name_cn =#{finance_para})
and (finance.order_no=#{orderNo})
and party.role_name=#{rolename_para}
AND financeOrder.party_id in
#{item}
and financeOrder.state=#{status_para}
and financeOrder.create_time >= #{createTime}
and financeOrder.close_time >= #{closeTime}
order by financeOrder.create_time desc
